{
  "family": "Reformatsky Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)C",
      "BrCC(=O)OCC"
    ],
    "product_smiles": [
      "CC(O)(C)CC(=O)OCC"
    ],
    "optional_reagent_smiles": [
      "[Zn]"
    ],
    "rationale": "This is the classic textbook example of the Reformatsky reaction, featuring the reaction of ethyl bromoacetate with acetone, mediated by zinc. It clearly demonstrates the formation of a \u03b2-hydroxy ester from an \u03b1-halo ester and a simple ketone. The reactants and product are small, acyclic, and lack complex functional groups, making it a canonical and unambiguous representation of this reaction family.",
    "collision_avoidance_note": "The reaction uses simple, acyclic aliphatic substrates to avoid overlap with reactions involving aromatic rings (e.g., Friedel-Crafts), complex ring systems, or other highly reactive functional groups. The specific combination of an \u03b1-halo ester and a ketone to form a \u03b2-hydroxy ester is characteristic of the Reformatsky reaction and distinct from other aldol-type or organometallic additions."
  }
}
